Then on the JavaScript `LeafletMapView` class you could, on mouse events, choose which style is applied.
Something like:
```javascript
leaflet_events: function () {
    var that = this;
    this.obj.on('movestart', function (e) {
        this.model.get('default_style').unstyle();
        this.model.get('dragging_style').style();
    }
    this.obj.on('moveend', function (e) {
        this.model.get('dragging_style').unstyle();
        this.model.get('default_style').style();
    }
    // ...
}
```
